use std::io::{self, Read};
fn solve_case(s: &str, words: &[String]) -> Vec<usize> { if words.is_empty() { return vec![]; } let wlen = words[0].len(); let total = wlen * words.len(); let mut target = words.to_vec(); target.sort(); let mut ans = Vec::new(); for i in 0..=s.len().saturating_sub(total) { if i + total > s.len() { break; } let mut parts = Vec::new(); for j in 0..words.len() { parts.push(s[i + j*wlen .. i + (j+1)*wlen].to_string()); } parts.sort(); if parts == target { ans.push(i); } } ans }
fn main(){ let mut input=String::new(); io::stdin().read_to_string(&mut input).unwrap(); if input.is_empty(){return;} let lines: Vec<&str>=input.split('\n').map(|s|s.trim_end_matches('\r')).collect(); let mut idx=0usize; let t: usize=lines[idx].trim().parse().unwrap_or(0); idx+=1; let mut out=Vec::new(); for _ in 0..t { let s=lines.get(idx).copied().unwrap_or("").to_string(); idx+=1; let m: usize=lines.get(idx).unwrap_or(&"0").trim().parse().unwrap_or(0); idx+=1; let mut words=Vec::new(); for _ in 0..m { words.push(lines.get(idx).copied().unwrap_or("").to_string()); idx+=1; } out.push(format!("[{}]", solve_case(&s,&words).iter().map(|v|v.to_string()).collect::<Vec<_>>().join(","))); } print!("{}", out.join("\n")); }
